const cmdId = 'cmd_' + Date.now().toString(36) + '_' + Math.random().toString(36).slice(2, 6);
const intent = $json.intent || '';
const params = $json.intentParams || {};
const text = $json.inputText || '';

let action, commandParams, requiresConfirmation;

switch (intent) {
  case 'local_screenshot':
    action = 'screenshot';
    commandParams = { monitor: params.monitor || 0 };
    requiresConfirmation = false;
    break;
  case 'local_browser':
    action = params.action || 'open';
    commandParams = { url: params.url || text.match(/https?:\/\/[^\s]+/)?.[0] || 'https://google.com' };
    requiresConfirmation = false;
    break;
  case 'local_app':
    action = 'app_open';
    commandParams = { app_name: params.app || text.split(' ').slice(-1)[0] };
    requiresConfirmation = false;
    break;
  case 'local_file':
    action = params.file_action || 'list';
    commandParams = { path: params.path || '~' };
    requiresConfirmation = ['delete', 'move'].includes(action);
    break;
  case 'local_shell':
    action = 'shell_exec';
    commandParams = { command: params.command || text };
    requiresConfirmation = true;
    break;
  default:
    action = 'system_info';
    commandParams = {};
    requiresConfirmation = false;
}

return [{ json: {
  ...$json,
  bridgeCommand: {
    command_id: cmdId,
    action,
    params: commandParams,
    requires_confirmation: requiresConfirmation,
    timeout_ms: 30000
  }
} }];

